"""
mkt-christ | 1kings | ch12–14 fill (4 verses already present; 94 missing)
run: python3 scripts/zc-christ-1kings-12-14-fill.py
"""

import json, pathlib

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS = {
  "12": {
    "1": "<p>A type: Shechem — the ancient covenant site where Joshua renewed the covenant with all Israel (Josh 24:1) and where Abimelech made himself king (Judg 9) — now becomes the site where the Davidic covenant fractures. The covenant assembly at Shechem ends not in renewal but in rupture. The typological irony intensifies in the NT: the church as the renewed-covenant assembly is gathered not at Shechem but around Christ, in whom 'all the promises of God find their Yes' (2 Cor 1:20).</p>",
    "2": "<p>A shadow: Jeroboam returns from Egypt — the land of slavery that Israel left in the Exodus. His return to Israel from Egypt reverses the Exodus direction and signals a counter-narrative: the new 'exodus leader' who will not bring Israel out of bondage but deepen it through idolatry. Contrast with Christ's own Egypt-return (Matt 2:15, fulfilling Hos 11:1) — the true Son called out of Egypt to accomplish the real exodus from sin and death.</p>",
    "3": "<p>A theme: All Israel assembled — the unified nation presenting its petition to the king. The legitimate grievance about heavy burdens sets up the contrast with Jesus's invitation: 'Come to me, all who labor and are heavy laden, and I will give you rest. Take my yoke upon you... for my yoke is easy and my burden is light' (Matt 11:28-30). The people asking for lighter yoke anticipates the one who actually provides it, not merely promises it.</p>",
    "4": "<p>A theme: 'Your father made our yoke heavy. Now therefore lighten the hard service of your father and his heavy yoke on us, and we will serve you.' The burden of Solomon's corvée labor is the specific grievance. The people's desire for a king who lightens burdens is a desire Christ alone fulfills — he who came 'not to be served but to serve, and to give his life as a ransom for many' (Matt 20:28), taking the heaviest burden upon himself.</p>",
    "5": "<p>A shadow: 'Go away for three days, then come to me again.' Rehoboam's three-day deliberation creates an inadvertent typological frame — the three days that will matter most in Israel's history are not these, but the three days of Christ's death and resurrection. The king's delay here is indecision; the three days of the tomb are the purposeful working of salvation.</p>",
    "6": "<p>A theme: The elder counsel — 'If you will be a servant to this people today and serve them and speak good words to them when you answer them, then they will be your servants forever.' The elders' wisdom about servant-leadership is the political form of what Jesus embodies perfectly: 'whoever would be great among you must be your servant, and whoever would be first among you must be slave of all' (Mark 10:43-44). The king who serves retains loyalty; Rehoboam rejects this wisdom.</p>",
    "7": "<p>A theme: 'If you will be a servant to this people and serve them...' — the servant-king model the elders articulate is the christological template. Isaiah's servant songs describe the Messiah as the one who does not break the bruised reed, serves rather than dominates, and through his servitude accomplishes the redemption that lordship cannot. The elders unwittingly describe the Christ.</p>",
    "8": "<p>A shadow: Rehoboam forsakes the counsel of the elders. The rejection of wisdom by the young king is the foil to Christ, 'in whom are hidden all the treasures of wisdom and knowledge' (Col 2:3). 1 Cor 1:20: 'Has not God made foolish the wisdom of the world?' The world's wisdom rejects the cross; the cross is the wisdom of God. Rehoboam choosing flattery over truth patterns the foolishness that ultimately destroys.</p>",
    "9": "<p>A shadow: Rehoboam asks the young men what to answer. The substitution of peer approval for wisdom is the dynamic Jesus exposes: 'How can you believe, when you receive glory from one another and do not seek the glory that comes from the only God?' (John 5:44). The king who asks the wrong counselors gets the wrong answer — and the wrong answer fractures the kingdom.</p>",
    "10": "<p>A shadow: 'My little finger is thicker than my father's waist.' The boast of greater severity — inverting the servant-king model — is the posture of the kingdoms of this world. Contrast with Phil 2:5-8: Christ 'did not count equality with God a thing to be grasped, but emptied himself... humbled himself by becoming obedient to the point of death.' Rehoboam's posture is the anti-incarnation: grasping at power while Christ emptied himself of it.</p>",
    "11": "<p>A shadow: 'My father chastised you with whips, but I will chastise you with scorpions.' The escalating threat — whips to scorpions — is the logic of coercive power that cannot ultimately hold the kingdom together. The kingdom held together by force fractures; the kingdom built on self-giving love endures: 'of the increase of his government and of peace there will be no end' (Isa 9:7).</p>",
    "12": "<p>A shadow: All Israel returned to Rehoboam on the third day as the king had said. The assembly on the third day receives the harsh answer. The third day that brings good news in the gospel — 'he was raised on the third day' (1 Cor 15:4) — contrasts with this third day that brings oppression. Israel's history is punctuated by third-day moments; the decisive one transforms all the others.</p>",
    "13": "<p>A shadow: Rehoboam answered the people harshly, forsaking the counsel of the elders. The hardening of the king's heart mirrors Pharaoh's hardening in Exodus — both produce an exodus from oppression. YHWH is at work in both hardenings to bring about his redemptive purposes (v15: 'this was a turn of affairs brought about by YHWH'). The pattern of oppressive king leading to exodus is rerun in eschatological form in Revelation, where the beast's persecution drives the exodus of the redeemed.</p>",
    "14": "<p>A shadow: 'I will add to your yoke. My father disciplined you with whips, but I will discipline you with scorpions.' The promised severity makes the break inevitable. The harsh yoke prophesied here is the yoke Christ specifically contrasts with his own: 'my yoke is easy and my burden is light' (Matt 11:30). Every oppressive yoke in Israel's history heightens the longing for the liberating king.</p>",
    "16": "<p>A type: 'What portion do we have in David? We have no inheritance in the son of Jesse.' The rejection of David's house — echoing Sheba's revolt (2 Sam 20:1) — is a type of the rejection of David's ultimate Son. John 19:15: 'We have no king but Caesar.' The cry that severs Israel from the Davidic covenant in v16 is echoed in the Passion when the crowd explicitly disclaims the Messianic king. Both rejections are permitted within YHWH's sovereign purposes for ultimate redemption.</p>",
    "17": "<p>A shadow: Only those living in the cities of Judah stayed with Rehoboam. The remnant of the Davidic covenant — Judah and Benjamin — is the lineage through which the Messiah will come. From this diminished but surviving kingdom, the line of David continues to Jesus. The covenant promise cannot be fully severed even when the kingdom divides.</p>",
    "18": "<p>A shadow: Adoram sent to collect the forced labor was stoned to death. The king's emissary killed by the people — rejected and stoned — is a pattern Jesus applies to the prophets (Matt 23:37: 'you stone those who are sent to you') and to himself in the parable of the wicked tenants (Matt 21:35-39). Adoram is among the long line of rejected messengers climaxing in the rejected Son.</p>",
    "19": "<p>A shadow: 'So Israel has been in rebellion against the house of David to this day.' The ongoing rebellion against David's house frames the entire subsequent narrative as an era of broken covenant. The NT frames Israel's history culminating in the rejection of the ultimate Davidic king: 'He came to his own, and his own people did not receive him' (John 1:11). But where that reception is granted, 'he gave the right to become children of God' (John 1:12).</p>",
    "20": "<p>A shadow: Jeroboam made king over all Israel while only Judah followed the house of David. The divided kingdom — the northern ten tribes under a counter-king — mirrors the ecclesiological tension Paul addresses in Romans 9-11: Israel divided, with a remnant according to grace in Judah while the majority pursues a different course. Paul's hope for 'all Israel' (Rom 11:26) looks toward the end of this division through the Messianic ingathering.</p>",
    "21": "<p>A shadow: Rehoboam assembled 180,000 chosen warriors to fight against the house of Israel to restore the kingdom. The impulse to retake by force what has been lost politically — reversing the division through war — is the human solution. The divine solution is not political restoration through violence but covenantal renewal through the Spirit. The church is gathered not by military might but by the proclamation of the gospel.</p>",
    "22": "<p>A revelation of God: The word of YHWH came to Shemaiah the man of God — divine intervention into the political crisis. YHWH speaks through his prophet to restrain human violence. The divine word that stops a war is the pattern of the peacemaking God: 'he himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility' (Eph 2:14). Christ is the ultimate Shemaiah — the one through whom YHWH's restraining word of peace goes out.</p>",
    "23": "<p>A revelation of God: 'Say to Rehoboam son of Solomon, king of Judah, and to all the house of Judah and Benjamin, and to the rest of the people.' The word of God addresses kings and people alike — no one is above the divine word. 2 Tim 3:16-17: 'All Scripture is breathed out by God and profitable for teaching, for reproof, for correction.' The word that reaches king and commoner equally is fulfilled in Christ who speaks with authority 'not as the scribes' (Matt 7:29).</p>",
    "24": "<p>A revelation of God: 'You shall not go up or fight against your brothers the people of Israel. Every man return to his home, for this thing is from me.' The divine word brings obedience: they listened to the word of YHWH and went home. The immediate obedience to the prophetic word is the type of the disciples' response to Jesus: 'Immediately they left their nets and followed him' (Matt 4:20). The word that commands and is obeyed demonstrates divine authority.</p>",
    "25": "<p>A shadow: Jeroboam built Shechem and Penuel — the counter-program to Solomon's building of the temple. The northern king builds political capitals rather than a house for YHWH; his construction program has no divine sanction. Jesus's building project is the church: 'I will build my church, and the gates of hell shall not prevail against it' (Matt 16:18). The divinely commissioned building is the community of the redeemed, not any human political structure.</p>",
    "26": "<p>A shadow: 'Jeroboam said in his heart, Now the kingdom will turn back to the house of David.' The fear-driven reasoning that leads to the golden calves — calculating that temple attendance will realign political loyalties — is the logic of pragmatic religion. Religion in service of politics, rather than politics in service of truth, characterizes the false shepherd. Christ's kingdom 'is not of this world' (John 18:36); his strategy is not political calculation but self-giving love.</p>",
    "27": "<p>A shadow: The fear of the people going to Jerusalem to offer sacrifices drives Jeroboam to create a substitute worship system. The substitution of convenient religion for true worship is what Jesus addresses in John 4:20-24 — the woman at the well asks about Jerusalem versus Gerizim and Jesus transcends the geography: 'true worshippers will worship the Father in spirit and truth.' Every substitute sanctuary finds its judgment in the one who says 'destroy this temple, and in three days I will raise it up' (John 2:19).</p>",
    "29": "<p>A shadow: He set one calf in Bethel and the other in Dan — the northern and southern boundaries of his kingdom. The golden calves installed at the borders of the northern kingdom create a counterfeit sacred geography to Jerusalem's temple. The NT's fulfillment of temple theology is Christ himself as the one in whom 'the whole fullness of deity dwells bodily' (Col 2:9). The counterfeit temples mark the absence of what Christ alone is.</p>",
    "30": "<p>A shadow: 'This became a sin, for the people went as far as Dan to worship before one.' The sin of Jeroboam — entrenched in the worship life of the northern kingdom — becomes the theological shorthand for apostasy throughout the books of Kings ('the sins of Jeroboam' is the repeated refrain). This concentrated sin is the OT illustration of what Paul calls worshipping and serving 'the creature rather than the Creator' (Rom 1:25).</p>",
    "31": "<p>A shadow: High places built, priests appointed from any tribe who were not Levites. The unauthorized priesthood — violating the Aaronic order — is the negative context in which the NT presents Christ as the perfect high priest. Heb 7:14-17: Jesus arose from Judah 'not according to a legal requirement concerning bodily descent but by the power of an indestructible life.' The legitimate priesthood is not hereditary claim but the power of the resurrection, making Jeroboam's unauthorized priests the negative type of Christ's indestructible priesthood.</p>",
    "32": "<p>A shadow: Jeroboam instituted a feast on the fifteenth day of the eighth month — one month after the divinely ordained Feast of Tabernacles (seventh month) — and offered on the altar at Bethel. The counterfeit calendar and counterfeit altar complete the counterfeit worship system. Paul's warning against being taken captive by human religious regulations (Col 2:16-23) addresses the same dynamic: human-devised feast-days that substitute for the substance found in Christ.</p>",
    "33": "<p>A shadow: Jeroboam went up to the altar to offer incense — the king arrogating priestly functions, mirroring Uzziah's presumption (2 Chr 26:16-20). The fusion of royal and priestly office was legitimate only in the Melchizedekan order — which Christ holds permanently (Heb 7:17). Every unauthorized priestly king in Israel is a counterfeit of the one legitimate Priest-King; every unauthorized incense-offering highlights the need for the one acceptable offering that Christ makes.</p>"
  },
  "13": {
    "1": "<p>A direct: A man of God came from Judah by the word of YHWH to Bethel. The prophet from Judah sent to confront false worship at Bethel is the type of the true Prophet from Judah — Jesus — who confronts false worship in his own temple-cleansing (John 2:13-22). Deut 18:15: 'YHWH your God will raise up for you a prophet like me from among you, from your brothers.' The man of God from Judah crying against Jeroboam's altar anticipates Christ's own prophetic confrontation with corrupt religious practice.</p>",
    "3": "<p>A direct: 'He gave a sign that same day: The altar will be torn apart, and the ashes that are on it shall be poured out.' The prophetic sign given immediately — the altar split and ashes poured — demonstrates that the divine word is not empty rhetoric but effective reality. Jesus's own sign of the temple destroyed and rebuilt in three days (John 2:19-22) is the ultimate prophetic sign: the sign of Jonah (Matt 12:39-40), the death and resurrection that validates all Jesus's words.</p>",
    "4": "<p>A direct: Jeroboam stretched out his hand from the altar, saying 'Seize him!' and his hand withered. The king's hand stretched out against God's prophet immediately judged — the hand that seized becomes the hand unable to withdraw. Compare Matt 12:13: Jesus restores a withered hand in the synagogue on the Sabbath, enacting the reversal of exactly this kind of divine judgment. The withered hand of Jeroboam reversed by YHWH at the prophet's prayer; the withered hand in Galilee restored by Christ — the same divine power applied now to healing rather than judgment.</p>",
    "5": "<p>A direct: The altar was torn apart and the ashes poured out, according to the sign the man of God had given by the word of YHWH. Prophetic fulfillment in real time. The sign given and immediately fulfilled establishes the pattern for understanding prophetic word and historical realization. The NT epistemic principle: 'if what a prophet says does not happen... that is a word the LORD has not spoken' (Deut 18:22). Every prophet who speaks and sees fulfillment — from the man of Judah here to Jesus himself — bears this authenticating mark.</p>",
    "6": "<p>A direct: 'Entreat now the favor of YHWH your God and pray for me, that my hand may be restored to me.' Jeroboam appeals to the prophet he tried to arrest — asking for intercession from the one he sought to silence. The intercessory power of the prophet of God over physical affliction points to Christ's intercessory office. Heb 7:25: 'he always lives to make intercession for them.' The king who asked the prophet to pray for him dimly anticipates all who approach Christ as their mediator.</p>",
    "7": "<p>A theme: 'Come home with me, and refresh yourself, and I will give you a reward.' Jeroboam's hospitality offer — immediately after the miraculous restoration — is the seductive gratitude that would compromise the prophet's mission. The prophet who accepts the king's table becomes the king's chaplain rather than his judge. Jesus refused the tempter's offers (Matt 4:3-10) and warned his disciples against seeking their own comfort when sent on mission (Luke 10:4 — 'carry no purse, no bag').</p>",
    "8": "<p>A theme: 'If you give me half your house, I will not go in with you. And I will not eat bread or drink water in this place.' The man of God's refusal is categorical — the divine commission prohibits all reciprocity with the false worship site. Total non-participation in idolatry is the standard set here, elaborated in Paul's instruction: 'Come out from them, and be separate from them' (2 Cor 6:17). The prophetic mission requires purity of association, not merely purity of message.</p>",
    "9": "<p>A theme: 'For it was commanded me by the word of YHWH, saying, You shall neither eat bread nor drink water nor return by the way that you came.' The man of God's obedience is grounded in specific divine command — not general principle but particular instruction. Jesus's obedience was similarly specific and total: 'I have not spoken on my own authority, but the Father who sent me has himself given me a commandment — what to say and what to speak' (John 12:49). Both prophets operate under precise divine instruction that cannot be modified by circumstance.</p>",
    "10": "<p>A shadow: He went another way and did not return by the way that he came to Bethel. The alternate return route — obedience to divine instruction even in logistics — is the pattern of vigilant obedience. The Magi also 'returned to their country by another way' (Matt 2:12) after the divine warning, a small detail that signals the same principle: those who receive the divine word structure their entire movement around it.</p>",
    "11": "<p>A shadow: An old prophet lived in Bethel. His sons come and tell him what the man of God did. The counterpart prophet in the false worship city — a resident of Bethel, not Judah — represents the compromised prophetic voice that has accommodated to the apostate system. His subsequent deception of the man of God warns against trusting prophetic authority detached from fidelity to the divine word. 1 John 4:1: 'do not believe every spirit, but test the spirits to see whether they are from God.'</p>",
    "12": "<p>A shadow: 'Where did he go?' — the old prophet inquires about the route of the man of God. The pursuit of the prophet who has left signals both curiosity and, as subsequent verses reveal, the old prophet's compromised intentions. The interrogation of the true prophet by those who have accommodated to false systems is a recurring pattern: 'Where do you come from? Where are you going?' — the questions asked of the stranger who disrupts the comfortable arrangement.</p>",
    "13": "<p>A shadow: 'Saddle the donkey for me.' The old prophet rides out in pursuit of the man of God from Judah. The donkey — the transport of prophets and kings (Zech 9:9, Jesus's triumphal entry) — carries the false prophet in his pursuit of the true. The contrast of transports is ironic: the true king enters Jerusalem on a donkey in humility; the deceiving prophet rides out to compromise the faithful messenger.</p>",
    "14": "<p>A shadow: 'Are you the man of God who came from Judah?' The old prophet confirms the identity. The scene in which a prophet identifies a prophet has a darker parallel in Jeroboam's wife going to Ahijah disguised (ch14:2) — encounters with prophets structured around concealment and revelation. In both cases, the prophet perceives what is hidden. Christ's knowledge of what is in man (John 2:25) fulfills this prophetic discernment perfectly.</p>",
    "15": "<p>A theme: 'Come home with me and eat bread.' The second offer of hospitality — now from a fellow prophet rather than a pagan king — is the more dangerous temptation because it appears legitimate. The man of God resisted the king's table but will be deceived by the prophet's lie. Galatians 2:11-14: Paul withstands Peter 'to his face' when Peter's behavior contradicted the gospel — even prophetic authority must be tested by the word of God.</p>",
    "16": "<p>A theme: 'I may not return with you, or go in with you. Neither will I eat bread nor drink water with you in this place.' The man of God repeats his commission categorically. Fidelity to divine instruction is not negotiable even when challenged by apparent peer authority. The warning of Gal 1:8 is the NT form: 'even if we or an angel from heaven should preach to you a gospel contrary to the one we preached to you, let him be accursed.' No authority — not a fellow prophet, not an angel — supersedes the original divine word.</p>",
    "17": "<p>A theme: 'I have been told by the word of YHWH: You shall neither eat bread nor drink water there.' The man of God's appeal to the specific divine word — repeated three times now (vv9, 16, 17) — is his only defense. He has no other authority. Paul similarly grounds every appeal in the gospel as received, not invented (Gal 1:11-12). The word of God as the only final authority is the principle the man of God articulates — and then fails to maintain.</p>",
    "18": "<p>A shadow: 'I also am a prophet as you are, and an angel spoke to me by the word of YHWH, saying Bring him back with you into your house that he may eat bread and drink water.' But he lied to him. The false prophet's lie — claiming angelic authority for a false message — is the exact scenario Paul warns against in Gal 1:8 ('even if an angel from heaven should preach another gospel'). The story in which the lie is not detected becomes the canonical warning against taking prophetic authority at face value: 'test the spirits' (1 John 4:1).</p>",
    "19": "<p>A shadow: The man of God went back with him and ate bread and drank water in his house. The failure of the man of God after such sustained faithfulness — deceived precisely at the point of his greatest vulnerability (a fellow prophet's credibility) — is a sobering study in how the godly fall. 1 Cor 10:12: 'let anyone who thinks he stands take heed lest he fall.' The pattern of sustained obedience followed by a single catastrophic failure runs through biblical history from Moses (Num 20) to Peter (Matt 26:69-74) to this unnamed prophet.</p>",
    "20": "<p>A shadow: As they sat at the table, the word of YHWH came to the old prophet who had brought him back. The irony is severe — the divine word now comes through the very prophet who lied to entrap the man of God. God uses even the false prophet to deliver his true word. This is the pattern of sovereign divine speech through unexpected vessels (Balaam's donkey, Caiaphas's unwitting prophecy, John 11:51). The word is not dependent on the worthiness of its instrument.</p>",
    "21": "<p>A direct: 'Thus says YHWH: Because you have disobeyed the word of YHWH and have not kept the command that YHWH your God commanded you...' The prophetic word of judgment on the disobedient prophet. The same word that commissioned him now condemns him. The word of God is the standard by which even prophets are judged — it is 'living and active, sharper than any two-edged sword, judging the thoughts and intentions of the heart' (Heb 4:12). Christ fulfills the law he proclaims; no one else does.</p>",
    "22": "<p>A shadow: 'Your body shall not come to the tomb of your fathers.' The specific judgment — dishonored burial — is the sign that the man of God's disobedience had real covenantal consequences. The concern for proper burial throughout the OT (Jacob, Joseph, David) points to the resurrection hope that Paul makes explicit: 'we await a Savior, the Lord Jesus Christ, who will transform our lowly body to be like his glorious body' (Phil 3:20-21). Improper burial is the shadow of resurrection denied; Christ's burial and resurrection are the guarantee of resurrection granted.</p>",
    "23": "<p>A shadow: After eating and drinking, the prophet who brought him back saddled the donkey for him. The seemingly normal departure — food, rest, the animal saddled — masks the judgment that is coming. The ordinary texture of life concealing divine action is the pattern of the incarnation: the eternal Word 'made flesh and dwelt among us' (John 1:14), living in the ordinary rhythms of human life while the decisive saving work proceeds beneath the surface.</p>",
    "24": "<p>A type: A lion met him on the road and killed him. The lion on the road as divine judgment — and yet the lion neither ate the body nor attacked the donkey (v28) — is a controlled sign-act. The lion as an agent of divine judgment that exercises precisely bounded restraint points forward to the Lion of Judah (Rev 5:5) who is also the Lamb that was slain — judgment and mercy in one figure. The restrained lion of v28 is the negative type; Christ who absorbs judgment into himself is the positive fulfillment.</p>",
    "25": "<p>A shadow: Some men passed by and saw the body lying in the road, with the lion standing beside the body. The public witness to the death and to the lion's unusual restraint is the sign that this is not ordinary death but divine judgment. The witnesses' report becomes testimony about divine action. The death of God's messenger publicly witnessed, the unusual circumstances making it unmistakably a divine act — this pattern of witnessed death-as-sign anticipates the public death of Christ, witnessed by many, whose unusual circumstances (darkness, torn curtain, earthquake) signal cosmic divine action (Matt 27:45-54).</p>",
    "26": "<p>A direct: 'It is the man of God who disobeyed the word of YHWH; therefore YHWH has given him to the lion, which has torn him and killed him according to the word that YHWH spoke to him.' The old prophet's interpretation of the death — faithfully attributing it to YHWH's word — shows that even the instrument of deception recognizes the divine authority of the word he manipulated. The death serves the word; the word is vindicated by the death. Christ's death is the ultimate vindication of the divine word: 'he became obedient to the point of death, even death on a cross' (Phil 2:8), and in that death every divine purpose for redemption is accomplished.</p>",
    "27": "<p>A shadow: He told his sons to saddle the donkey for him — returning to retrieve the body. The old prophet's act of retrieving and honoring the man of God's body, despite having deceived him, shows that the prophet's deception did not eliminate his recognition of the man of God's authentic commission. The body of the true prophet is honored even by the one who caused his death. The parallel with Joseph of Arimathea and Nicodemus — secret disciples who honor the body of Jesus — is structural: those who had not fully committed themselves in life show their genuine recognition in the act of burial.</p>",
    "28": "<p>A shadow: The lion standing beside the body — and beside the donkey — had neither eaten the body nor torn the donkey. The lion's restraint is the supernatural sign within the sign. The instrument of judgment stopped precisely at its appointed task, neither consuming nor expanding its destruction. The bounded nature of divine judgment — purposive, not consumptive — points to the cross where wrath is 'propitiated' (1 John 2:2) rather than exhausted, where judgment absorbs sin without consuming the sinner who is in Christ.</p>",
    "29": "<p>A shadow: The old prophet laid the body on the donkey and brought it back to the city to mourn and bury him. The old prophet mourning the man he had deceived — giving him an honorable burial — is an act of painful recognition. The interplay of culpability and honor in the burial points to the human condition before the cross: complicit in the death of the true messenger yet recognizing his worth. The theological condition Paul describes — 'I have the desire to do what is right, but not the ability to carry it out' (Rom 7:18).</p>",
    "30": "<p>A shadow: He laid the body in his own tomb and mourned over him, saying 'Alas, my brother!' The burial in the false prophet's own tomb — the deceiver providing his own resting place to the one he deceived — is a final irony. The prophet who had no tomb in his fathers' land rests in the tomb of his deceiver. Christ, who 'had nowhere to lay his head' (Matt 8:20), is buried in a borrowed tomb (Matt 27:60) — one not his own, which he would not need to keep.</p>",
    "31": "<p>A type: 'When I die, bury me in the tomb in which the man of God is buried; lay my bones beside his bones.' The old prophet's deathbed request to share the man of God's tomb transforms the site of judgment into a site of anticipated vindication. The bones of the faithful man have such sacred power that even the deceiver wishes to be near them at resurrection. 2 Kgs 13:21 — a dead man thrown into Elisha's tomb revives when he touches the bones — is the typological fulfillment. The bones of the righteous anticipate resurrection; Christ's empty tomb is the definitive reversal of the tomb as final resting place.</p>",
    "32": "<p>A direct: 'For the saying that he cried by the word of YHWH against the altar in Bethel... will surely come to pass.' Three centuries before Josiah's reform (2 Kgs 23:15-20), the prophecy naming Josiah stands as the outstanding example of specific predictive prophecy in the OT. The specificity of 'Josiah by name' anticipates the NT pattern of precisely named messianic prophecy: 'to be called a Nazarene' (Matt 2:23); 'they will look on me, the one they have pierced' (Zech 12:10; John 19:37). The God who names Josiah centuries early is the same God who names Jesus through his prophets.</p>",
    "33": "<p>A shadow: After this Jeroboam did not turn from his evil way, but made priests for the high places from among all the people. The apostasy that survives divine warnings and miraculous signs — the split altar, the restored hand, the dead prophet — is the hardness of heart that only the new covenant can address. Ezek 36:26: 'I will remove the heart of stone from your flesh and give you a heart of flesh.' The king who witnesses miracles and continues in sin illustrates why external signs alone do not produce repentance; only the Spirit's transforming work does.</p>",
    "34": "<p>A shadow: This thing became sin to the house of Jeroboam, so as to cut it off and to destroy it from the face of the earth. The dynasty-ending sin is formalized here — Jeroboam's apostasy has guaranteed his house will be swept away (fulfilled in ch15 under Baasha). The repeated pattern of dynasties raised and destroyed for apostasy is the OT's political expression of the principle that 'the wages of sin is death' (Rom 6:23). Only the dynasty of David, through whom the eternal King comes, survives — not by human faithfulness but by divine covenant promise (2 Sam 7:14-16).</p>"
  },
  "14": {
    "1": "<p>A shadow: At that time Abijah the son of Jeroboam became sick. The sick child of the king — the occasion for the oracle of judgment against Jeroboam — establishes the narrative frame for one of the most direct divine repudiations of a king in Kings. The sickness of the child who is the one good thing in Jeroboam's household (v13: 'he alone of Jeroboam's family shall come to the grave, because in him there is found something pleasing to YHWH') reflects the general pattern: in a world of sin, innocence suffers. Christ bears that suffering as 'the righteous for the unrighteous' (1 Pet 3:18).</p>",
    "2": "<p>A shadow: 'Arise and disguise yourself so that it not be known that you are the wife of Jeroboam.' The royal wife sent in disguise to a prophet — concealing her identity to manipulate the outcome — mirrors the general pattern of human deception before the all-seeing God. John 2:24-25: Christ 'knew what was in man'; he 'did not need anyone to testify about a person.' The disguise that fools no one before the prophet reveals the futility of concealing our true condition before God.</p>",
    "3": "<p>A shadow: 'Take with you ten loaves, some cakes, and a jar of honey, and go to him. He will tell you what shall happen to the child.' The quid pro quo approach to prophetic knowledge — bringing gifts to receive divine revelation — is the mercantile theology that the NT repudiates. Simon Magus tried to buy the Holy Spirit (Acts 8:18-20); Peter's rebuke: 'May your silver perish with you, because you thought you could obtain the gift of God with money.' The gift of divine knowledge, like the gift of salvation, is freely given, not commercially obtained.</p>",
    "4": "<p>A shadow: The wife of Jeroboam went to Shiloh — the ancient sanctuary site of the ark before Solomon's temple (1 Sam 1-4). The echoing of Shiloh in this narrative connects the collapse of Jeroboam's house with the prior collapse of Eli's house at Shiloh — both priestly/royal dynasties destroyed for corrupting the worship of YHWH. The pattern of judgment for desecrating the divine presence reaches its culmination when Christ, the divine presence made flesh, is himself violently rejected.</p>",
    "5": "<p>A revelation of God: YHWH said to Ahijah, 'The wife of Jeroboam is coming to inquire of you.' The divine foreknowledge given to the prophet is the OT mode of what Jesus demonstrates directly: 'Now we know that you know all things and do not need anyone to question you' (John 16:30). The prophet who knows the visitor before she arrives is the type of the prophet who 'knew what was in man' (John 2:25). Omniscience as a prophetic attribute is a creaturely participation in what Christ holds essentially.</p>",
    "6": "<p>A revelation of God: 'Come in, wife of Jeroboam. Why do you pretend to be another? For I am charged with unbearable news for you.' The prophet's greeting strips away the disguise instantly — the word of God sees through human concealment. Heb 4:13: 'no creature is hidden from his sight, but all are naked and exposed to the eyes of him to whom we must give account.' The prophet's penetrating sight is the OT form of the divine omniscience fully realized in Christ the Word.</p>",
    "7": "<p>A revelation of God: 'Go, tell Jeroboam, Thus says YHWH the God of Israel: Because I exalted you from among the people and made you leader over my people Israel...' The divine accounting of what YHWH gave Jeroboam — the ledger of grace before the verdict of judgment — is the pattern of the prophetic lawsuit (<em>rib</em>). God does not pronounce judgment without first establishing the gifts that were spurned. The gospel similarly sets the cross against the backdrop of divine generosity: 'What more could have been done for my vineyard than I have done for it?' (Isa 5:4).</p>",
    "9": "<p>A shadow: 'You have done more evil than all who were before you and have gone and made for yourself other gods and metal images, provoking me to anger, and have cast me behind your back.' The specific indictment — casting YHWH 'behind your back' — is the posture of the world Paul describes in Rom 1:21-23: 'Although they knew God, they did not honor him as God or give thanks to him... they exchanged the glory of the immortal God for images.' The golden calves are a specific case of the universal exchange. Christ reverses it: 'He is the image of the invisible God' (Col 1:15) — the true image, not the counterfeit.</p>",
    "10": "<p>A shadow: 'I will bring harm upon the house of Jeroboam and will cut off from Jeroboam every male, both bond and free in Israel.' The totality of the judgment — the dynasty erased — is the OT form of what Rev 20:11-15 describes eschatologically: final reckoning from which no one is exempt. The difference between Jeroboam's judgment and the final judgment is that Christ has interposed himself between the sinner and divine wrath: 'he himself is the propitiation for our sins' (1 John 2:2).</p>",
    "11": "<p>A shadow: 'Anyone belonging to Jeroboam who dies in the city the dogs shall eat, and anyone who dies in the field the birds of the heavens shall eat, for YHWH has spoken it.' The unburied dead — denied even burial — is the ultimate dishonor in the ancient world. The same judgment formula appears against Jezebel (1 Kgs 21:23) and against the fallen in the Day of YHWH (Ezek 39:17-20; Rev 19:17-21). The birds feasting on the fallen is the negative eschatological image reversed in Christ's resurrection: 'you will not let your Holy One see corruption' (Acts 2:27, Ps 16:10).</p>",
    "12": "<p>A type: 'Arise therefore, go to your house. When your feet enter the city, the child shall die.' The divine timing of the child's death — coordinated with the mother's return — establishes the prophetic word as the sovereign governor of events. The 'hour' appointed by YHWH is a recurring theme: 'My hour has not yet come' (John 2:4) and 'the hour has come' (John 17:1) — the divine calendar governing the key moments of redemption history, fulfilled ultimately in the hour of the cross.</p>",
    "13": "<p>A type: 'And all Israel shall mourn for him and bury him, for he alone of Jeroboam's family shall come to the grave, because in him there is found something pleasing to YHWH God of Israel, in the house of Jeroboam.' The one good child in the wicked dynasty — whose early death is an act of grace, removing him before he sees the dynasty's destruction — is a type of the principle that divine mercy preserves what is pleasing to YHWH while judgment falls on what is corrupt. The remnant theology expressed here: within the condemned house, the one with any good in him is spared. Christ is the ultimate pleasing one (Matt 3:17: 'This is my beloved Son, with whom I am well pleased') in whom all who are 'in him' receive the Father's pleasure.</p>",
    "14": "<p>A shadow: 'YHWH will raise up for himself a king over Israel who shall cut off the house of Jeroboam today. And henceforth, what? Even now.' The sovereign raising up of a new king — Baasha (fulfilled 15:28-29) — demonstrates that YHWH controls the succession of earthly powers. Dan 2:21: 'He removes kings and sets up kings.' The ultimate king YHWH raises up is not Baasha but the Son of David — the one who ends all failed kingships by inaugurating the eternal kingdom (Luke 1:32-33).</p>",
    "15": "<p>A shadow: 'YHWH will strike Israel as a reed is shaken in the water, and root up Israel out of this good land that he gave to their fathers and scatter them beyond the Euphrates.' The coming exile — the Assyrian deportation of the northern kingdom (2 Kgs 17) — is prophesied here over a century before it happens. The scattering of Israel into exile is the covenant-curse realized (Deut 28:64-68). The gospel answers the exile: 'to gather into one the children of God who are scattered abroad' (John 11:52) — Christ's death accomplishing the ingathering that the prophets anticipate.</p>",
    "16": "<p>A shadow: 'He will give Israel up because of the sins of Jeroboam, which he sinned and made Israel to sin.' The theological summary — YHWH 'giving up' Israel — is the strongest expression of divine judgment in the OT royal narrative, paralleled only by Paul's three-fold 'God gave them up' in Rom 1:24-28. The abandonment to the consequences of chosen sin is the severest form of judgment. The opposite of being given up is being 'given' — 'God so loved the world that he gave his only Son' (John 3:16). The Son given for the world is the answer to the world that YHWH gives up.</p>",
    "17": "<p>A theme: Jeroboam's wife arose and departed. The fulfillment of Ahijah's word is immediate and exact: she goes to Tirzah and the child dies as she crosses the threshold. The precision of prophetic fulfillment — down to the exact moment — establishes the reliability of divine prediction. Peter's principle: 'no prophecy was ever produced by the will of man, but men spoke from God as they were carried along by the Holy Spirit' (2 Pet 1:21). The word that predicts the child's death at the doorstep is the same Spirit-carried word that predicts the Servant who will die for the people's sins.</p>",
    "18": "<p>A theme: All Israel buried him and mourned for him, according to the word of YHWH which he spoke by his servant Ahijah the prophet. The fulfillment formula — 'according to the word of YHWH which he spoke by' — is the standard phrase that runs through Kings connecting prophecy to fulfillment. Luke's birth narrative uses the same structure repeatedly: 'as it is written in the Law of the Lord' (Luke 2:23); 'according to what is said in the Law of the Lord' (Luke 2:24). The pattern of word → fulfillment that structures Kings reaches its apex in Christ, the one of whom it is said 'all this took place to fulfill what the Lord had spoken by the prophet' (Matt 1:22).</p>",
    "19": "<p>A shadow: The rest of the acts of Jeroboam, how he warred and how he reigned, are written in the Book of the Chronicles of the Kings of Israel. The archival reference — 'written in the Book of the Chronicles' — represents the full record of a reign reduced to a summary judgment. The ultimate books that matter are the 'books' opened at the last judgment (Rev 20:12) — and the one book that determines eternal standing is the 'book of life of the Lamb' (Rev 21:27).</p>",
    "20": "<p>A shadow: Jeroboam reigned twenty-two years and slept with his fathers, and Nadab his son reigned in his place. The regnal summary — years, death, succession — marks every northern king until the dynasty ends in assassination. The contrast with David, of whom it is said 'your throne shall be established forever' (2 Sam 7:16), underscores the temporary nature of all earthly kingship compared to the eternal Davidic covenant fulfilled in Christ, 'who was raised from the dead, descendant of David, according to my gospel' (2 Tim 2:8).</p>",
    "21": "<p>A shadow: Rehoboam the son of Solomon reigned in Judah. He was forty-one years old when he began to reign, and he reigned seventeen years in Jerusalem, the city that YHWH had chosen out of all the tribes of Israel, to put his name there. The repeated emphasis on Jerusalem as 'the city YHWH had chosen to put his name there' keeps the Davidic covenant and the temple theology in view even through the narrative of Rehoboam's failure. The name of YHWH placed in Jerusalem ultimately arrives in person: 'I am the way, and the truth, and the life' (John 14:6) — the name that is above every name (Phil 2:9) present in the city of David.</p>",
    "22": "<p>A shadow: Judah did what was evil in the sight of YHWH, and they provoked him to jealousy with their sins that they committed, more than all that their fathers had done. The southern kingdom's apostasy — not as severe as the north but equally real — establishes that the covenant failure is not limited to Jeroboam's corrupted north. The letter to the Romans demonstrates the same universal diagnosis: 'all, both Jews and Greeks, are under sin' (Rom 3:9). The universal failure of Jew and Gentile alike makes the universal atonement of Christ necessary and sufficient.</p>",
    "23": "<p>A shadow: They also built for themselves high places and pillars and Asherim on every high hill and under every green tree. The proliferation of unauthorized worship sites — 'every high hill and under every green tree' — is the OT image of the human tendency toward religious multiplication that substitutes local, convenient, self-designed worship for the prescribed approach to the one true God. Jesus's conversation with the Samaritan woman resolves this: worship is no longer about location — Jerusalem or Gerizim — but about spirit and truth (John 4:21-24), a worship that Christ himself mediates.</p>",
    "24": "<p>A shadow: There were also male cult prostitutes in the land. They did according to all the abominations of the nations that YHWH drove out before the people of Israel. The full descent into Canaanite religious practice — including cult prostitution — completes the picture of wholesale apostasy. The irony is that Israel has become what it was commissioned to displace. Paul in Rom 1:18-32 describes the same devolution: the suppression of truth about God leads through idolatry to sexual immorality. The solution is not better law but the 'righteousness of God revealed through faith' (Rom 1:17) — the gospel.</p>",
    "25": "<p>A shadow: In the fifth year of King Rehoboam, Shishak king of Egypt came up against Jerusalem. Egypt — the land of slavery from which YHWH had brought Israel out in the Exodus — now returns as the instrument of judgment against the apostate kingdom. The reversal of the Exodus: Pharaoh's successor plunders what the Exodus generation built. The ultimate reversal of this reversal is the new exodus accomplished in Christ: 'He has delivered us from the domain of darkness and transferred us to the kingdom of his beloved Son' (Col 1:13), a transfer that cannot be reversed by any earthly power.</p>",
    "26": "<p>A shadow: He took away the treasures of the house of YHWH and the treasures of the king's house. He took everything. He also took away all the shields of gold that Solomon had made. The stripping of the temple — Solomon's accumulated sacred treasures taken to Egypt — is the inversion of the Exodus plunder (Exod 12:35-36 where Egypt was stripped). The temple's glory progressively diminishes through the Kings narrative until it is destroyed. Christ's temple-body is stripped and crucified; through that stripping, the true treasure is revealed: 'the riches of the glory of this mystery, which is Christ in you, the hope of glory' (Col 1:27).</p>",
    "27": "<p>A shadow: King Rehoboam made in their place shields of bronze, and committed them to the hands of the officers. The substitution of bronze for gold — maintaining the appearance of royal splendor while the substance has been stripped — is the logic of institutional religion that preserves the form after the life has departed. Jesus's verdict on the scribes and Pharisees: 'whitewashed tombs, which outwardly appear beautiful, but within are full of dead people's bones' (Matt 23:27). Bronze replacing gold is the OT image of this formal-but-empty substitution.</p>",
    "28": "<p>A shadow: And as often as the king went into the house of YHWH, the guard carried them and brought them back to the guardroom. The routine of bronze shields carried out and brought back — the ceremony maintained without the gold reality — is the hollowed-out liturgical life that the prophets decry. Amos 5:21-24: 'I hate, I despise your feasts... let justice roll down like waters.' The form without the substance is the condition Christ comes to transform: 'God is spirit, and those who worship him must worship in spirit and truth' (John 4:24).</p>",
    "29": "<p>A shadow: The rest of the acts of Rehoboam and all that he did, are they not written in the Book of the Chronicles of the Kings of Judah? The archival reference closes the Rehoboam account. The human chronicle of kings — acts, wars, years — points to the divine chronicle of the King of kings: 'Jesus did many other things as well. If every one of them were written down, I suppose that even the whole world would not have room for the books that would be written' (John 21:25). The royal archive that matters most cannot be contained.</p>",
    "30": "<p>A shadow: And there was war between Rehoboam and Jeroboam continually. The perpetual war between the divided kingdoms — north against south, Israelite against Israelite — is the covenant fracture made military. Paul's vision of the church as the reconciled community is the eschatological answer: 'there is neither Jew nor Greek, there is neither slave nor free, there is no male and female, for you are all one in Christ Jesus' (Gal 3:28). The wall of hostility that Christ tears down (Eph 2:14) is the same wall whose OT expression was this intra-Israelite warfare.</p>",
    "31": "<p>A shadow: Rehoboam slept with his fathers and was buried with his fathers in the city of David. His mother's name was Naamah the Ammonitess. And Abijam his son reigned in his place. The regnal death formula — sleep with fathers, buried in the city of David — closes the Rehoboam account. His Ammonite mother is noted: the foreign influence that helped shape the king who divided the kingdom. The succession continues, the covenant promise to David maintained despite the king's failures. Christ as the final Davidic heir is the terminus of this succession: 'the kingdom will be established forever' (2 Sam 7:16) through the one death that does not end in permanent sleep but in resurrection.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '1kings')
    merge_comm(existing, KINGS)
    save_comm('mkt-christ', '1kings', existing)
    print('1 Kings 12-14 christ written.')

if __name__ == '__main__':
    main()
